__kernel void dynproc_kernel(
    int pyramid_height,
    __global const int* wall,
    __global const int* src,
    __global int* dst,
    int cols,
    int rows,
    int t_start,
    int borderCols,
    int halo,
    __local int* local_src,
    __local int* local_dst,
    __global int* outputBuffer)
{
    int gid = get_global_id(0);
    int lid = get_local_id(0);
    int lsize = get_local_size(0);

    if (gid >= cols) return;

    int current_row = t_start;
    int steps = pyramid_height;

    // Pointers to current source and destination within the iteration
    __global const int* cur_src = src;
    __global int* cur_dst = dst;

    for (int step = 0; step < steps; step++) {
        int row_idx = current_row + step;
        if (row_idx >= rows - 1) break;

        int val = cur_src[gid];
        if (gid > 0) {
            int left = cur_src[gid - 1];
            if (left < val) val = left;
        }
        if (gid < cols - 1) {
            int right = cur_src[gid + 1];
            if (right < val) val = right;
        }

        cur_dst[gid] = wall[row_idx * cols + gid] + val;

        // Swap pointers for next iteration if not the last step
        if (step < steps - 1) {
            __global const int* temp_src = cur_src;
            cur_src = cur_dst;
            cur_dst = (__global int*)temp_src;
        }
    }
}
